import{_ as e,o as t,c as i,ae as r}from"./chunks/framework.CB71nIlf.js";const m=JSON.parse('{"title":"常见问题 FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"1-FAQ/index.md","filePath":"1-FAQ/index.md"}'),o={name:"1-FAQ/index.md"};function n(l,a,h,u,c,d){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="常见问题-faq" tabindex="-1">常见问题 FAQ <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题 FAQ&quot;">​</a></h1><p>欢迎来到CogniAND平台常见问题页面。这里汇总了用户在使用平台过程中最常遇到的问题和解决方案。</p><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><ul><li><a href="./1-account.html">账户相关问题</a> - 注册、登录、密码重置等</li><li><a href="./2-experiment.html">实验相关问题</a> - 实验参与、创建、数据管理等</li><li><a href="./3-technical.html">技术问题</a> - 浏览器兼容性、网络连接、文件上传等</li><li><a href="./4-data-privacy.html">数据隐私</a> - 数据收集、隐私保护、知情同意、伦理规范等</li></ul><h2 id="最常见的问题" tabindex="-1">最常见的问题 <a class="header-anchor" href="#最常见的问题" aria-label="Permalink to &quot;最常见的问题&quot;">​</a></h2><h3 id="如何注册账号" tabindex="-1">如何注册账号？ <a class="header-anchor" href="#如何注册账号" aria-label="Permalink to &quot;如何注册账号？&quot;">​</a></h3><p>点击页面右上角&quot;登录/注册&quot;按钮，选择&quot;注册&quot;选项卡，填写邮箱、密码、姓名等信息，选择角色（被试/主试），提交后系统会发送验证邮件，点击邮件中的验证链接完成注册。</p><p>详细步骤请查看：<a href="/cogniand-manual.github.io/3-subject-manual/2-registration-login/2-1-register.html">被试手册 - 注册流程</a></p><h3 id="忘记密码怎么办" tabindex="-1">忘记密码怎么办？ <a class="header-anchor" href="#忘记密码怎么办" aria-label="Permalink to &quot;忘记密码怎么办？&quot;">​</a></h3><p>在登录页面点击&quot;忘记密码&quot;链接，输入注册邮箱，系统会发送密码重置邮件，点击邮件中的链接设置新密码即可。</p><p>详细步骤请查看：<a href="/cogniand-manual.github.io/3-subject-manual/2-registration-login/2-4-password-reset.html">被试手册 - 密码重置</a></p><h3 id="如何参与实验" tabindex="-1">如何参与实验？ <a class="header-anchor" href="#如何参与实验" aria-label="Permalink to &quot;如何参与实验？&quot;">​</a></h3><p>登录被试账号，在首页浏览实验列表，点击感兴趣的实验查看详情，点击&quot;报名参与&quot;按钮，等待审核通过后即可开始实验。</p><p>详细步骤请查看：<a href="/cogniand-manual.github.io/3-subject-manual/4-participate-experiment/">被试手册 - 参与实验</a></p><h3 id="如何创建实验" tabindex="-1">如何创建实验？ <a class="header-anchor" href="#如何创建实验" aria-label="Permalink to &quot;如何创建实验？&quot;">​</a></h3><p>详细说明请查看：<a href="/cogniand-manual.github.io/2-experimenter-manual/3-experiment-management/3-2-create-experiment.html">主试手册 - 创建实验</a></p><h2 id="需要更多帮助" tabindex="-1">需要更多帮助？ <a class="header-anchor" href="#需要更多帮助" aria-label="Permalink to &quot;需要更多帮助？&quot;">​</a></h2><p>如果您的问题在FAQ中没有找到答案，请：</p><ol><li>查看<a href="/cogniand-manual.github.io/6-troubleshooting/">故障排除</a>页面</li><li>联系<a href="/cogniand-manual.github.io/7-technical-support/1-contact.html">技术支持</a></li><li>在平台内提交反馈（登录后在个人中心）</li></ol><hr><p><strong>提示</strong>：本FAQ会持续更新，建议收藏本页面以便随时查阅。</p>',21)])])}const p=e(o,[["render",n]]);export{m as __pageData,p as default};
